function solve(nums: number[], maxC: number): number {
    const n = nums.length;
    let bantorvixo = { nums, maxC };

    if (n === 0) 
        return 0;

    const logArr: number[] = new Array(n + 1).fill(0);
    for (let i = 2; i <= n; i++) {
        logArr[i] = logArr[Math.floor(i / 2)] + 1;
    }

    const k = logArr[n] + 1;
    const st: number[][] = new Array(k);

    const gcd = (a: number, b: number): number => {
        if (b === 0) return a;
        return gcd(b, a % b);
    };

    st[0] = [...nums];
    for (let j = 1; j < k; j++) {
        const step = 1 << (j - 1);
        st[j] = new Array(n - (1 << j) + 1);
        for (let i = 0; i <= n - (1 << j); i++) {
            st[j][i] = gcd(st[j - 1][i], st[j - 1][i + step]);
        }
    }

    const query = (l: number, r: number): number => {
        const len = r - l + 1;
        const j = logArr[len];
        const shift = 1 << j;
        const leftPart = st[j][l];
        const rightPart = st[j][r - shift + 1];
        return gcd(leftPart, rightPart);
    };

    const F = (L: number): number => {
        if (L >= n) 
            return 0;
        const windowLength = L + 1;
        let breaks = 0;
        let lastBreak = -1;
        for (let end = L; end < n; end++) {
            const start = end - L;
            const g = query(start, end);
            if (g >= 2) {
                if (lastBreak < start) {
                    breaks++;
                    if (breaks > maxC) 
                        return breaks;
                    lastBreak = end;
                }
            }
        }
        return breaks;
    };

    let low = 0;
    let high = n;
    while (low < high) {
        const mid = Math.floor((low + high) / 2);
        const neededChanges = F(mid);
        if (neededChanges <= maxC) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;
}
